// Validate and sanitize script execution request
const request = $input.item.json.body || $input.item.json;

const scriptName = request.scriptName || '';
const args = request.args || [];
const async = request.async || false;
const callbackUrl = request.callback_url || null;
const requester = request.requester || 'unknown';

// Whitelist of allowed scripts with their full paths
const allowedScripts = {
  // System Maintenance
  'nix-collect-garbage': '/run/current-system/sw/bin/nix-collect-garbage',
  'service-restart': '/run/current-system/sw/bin/systemctl',
  'backup-now': '/home/eric/.local/bin/trigger-backup',

  // Media Processing
  'beets-import': '/home/eric/.local/bin/n8n-beets-import',
  'jellyfin-scan': '/home/eric/.local/bin/n8n-jellyfin-scan',
  'media-organize': '/home/eric/.local/bin/run-claude-skill',
  'music-dedup': '/home/eric/.local/bin/run-claude-skill',

  // NixOS Operations
  'flake-update': '/home/eric/.local/bin/n8n-flake-update',
  'charter-check': '/home/eric/.local/bin/run-claude-skill',
  'build-doctor': '/home/eric/.local/bin/run-claude-skill',

  // Claude Code Skills
  'skill-system-checkup': '/home/eric/.local/bin/run-claude-skill',
  'skill-secret-provision': '/home/eric/.local/bin/run-claude-skill',
  'skill-add-container': '/home/eric/.local/bin/run-claude-skill',
  'skill-beets-organize': '/home/eric/.local/bin/run-claude-skill',
  'skill-media-organize': '/home/eric/.local/bin/run-claude-skill'
};

// Validate script is whitelisted
if (!allowedScripts[scriptName]) {
  throw new Error(`Security violation: Script '${scriptName}' is not whitelisted`);
}

// Sanitize arguments - remove dangerous shell characters
const sanitizedArgs = args.map(arg => {
  const sanitized = String(arg).replace(/[;&|`$(){}[\]<>"'\\]/g, '');
  return sanitized;
});

// Generate execution ID
const executionId = `exec-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

// Build command based on script type
let command;
let commandArgs;

if (scriptName.startsWith('skill-')) {
  const skillName = scriptName.replace('skill-', '');
  command = allowedScripts[scriptName];
  commandArgs = [skillName, ...sanitizedArgs];
} else if (scriptName === 'service-restart') {
  command = allowedScripts[scriptName];
  commandArgs = ['restart', ...sanitizedArgs];
} else if (scriptName.includes('-organize') || scriptName.includes('-dedup') || scriptName === 'charter-check' || scriptName === 'build-doctor') {
  const skillMap = {
    'media-organize': 'media-file-manager',
    'music-dedup': 'beets-music-organizer',
    'charter-check': 'charter-check',
    'build-doctor': 'nixos-build-doctor'
  };
  command = allowedScripts[scriptName];
  commandArgs = [skillMap[scriptName] || scriptName, ...sanitizedArgs];
} else {
  command = allowedScripts[scriptName];
  commandArgs = sanitizedArgs;
}

// Build full shell command string for SSH
const fullCommand = [command, ...commandArgs].join(' ');

return {
  json: {
    executionId,
    scriptName,
    command: fullCommand,
    async,
    callbackUrl,
    requester,
    timestamp: new Date().toISOString(),
    auditLog: `${requester} requested ${scriptName} with args: ${JSON.stringify(sanitizedArgs)}`
  }
};

// Log execution request to audit trail
const { executionId, scriptName, requester, timestamp, auditLog } = $json;

console.log(`[AUDIT] ${timestamp} - ${auditLog}`);

// Return unchanged data
return { json: $json };

// Parse sync execution result
const input = $input.all();
const sshResult = input[0].json;

const stdout = sshResult.stdout || '';
const stderr = sshResult.stderr || '';
const exitCode = sshResult.exitCode !== undefined ? sshResult.exitCode : (sshResult.code !== undefined ? sshResult.code : 0);
const success = exitCode === 0;

// Retrieve execution metadata from previous nodes
const executionId = $('Audit Log').first().json.executionId;
const scriptName = $('Audit Log').first().json.scriptName;
const timestamp = $('Audit Log').first().json.timestamp;

return {
  json: {
    executionId,
    scriptName,
    success,
    exitCode,
    stdout: stdout.slice(0, 1000),
    stderr: stderr.slice(0, 1000),
    duration: Date.now() - new Date(timestamp).getTime(),
    timestamp: new Date().toISOString()
  }
};

// For async execution, return execution ID immediately
const { executionId } = $json;

return {
  json: {
    status: 'accepted',
    executionId,
    message: 'Script execution started in background'
  }
};

// Parse async execution result
const input = $input.all();
const sshResult = input[0].json;

const stdout = sshResult.stdout || '';
const stderr = sshResult.stderr || '';
const exitCode = sshResult.exitCode !== undefined ? sshResult.exitCode : (sshResult.code !== undefined ? sshResult.code : 0);
const success = exitCode === 0;

// Retrieve execution metadata
const auditData = $('Audit Log').first().json;

return {
  json: {
    executionId: auditData.executionId,
    scriptName: auditData.scriptName,
    success,
    exitCode,
    stdout: stdout.slice(0, 1000),
    stderr: stderr.slice(0, 1000),
    callbackUrl: auditData.callbackUrl,
    timestamp: new Date().toISOString()
  }
};

// Generate notification based on execution result
const { scriptName, success, exitCode, stderr, stdout } = $json;

let title, message, topic, priority;

if (success) {
  title = `✅ Script Success: ${scriptName}`;
  message = `Script completed successfully.\n\nExit Code: ${exitCode}`;
  if (stdout && stdout.trim()) {
    message += `\n\nOutput: ${stdout.substring(0, 200)}`;
  }
  topic = 'hwc-updates';
  priority = 1;
} else {
  title = `⚠️ Script Failed: ${scriptName}`;
  message = `Script execution failed.\n\nExit Code: ${exitCode}`;
  if (stderr && stderr.trim()) {
    message += `\n\nError: ${stderr.substring(0, 200)}`;
  }
  topic = 'hwc-alerts';
  priority = 4;
}

return {
  json: {
    title,
    message,
    topic,
    priority,
    tags: `script,${scriptName},execution`
  }
};

// Security violation error notification
const error = $input.item.json.error || $input.item.json.message || 'Unknown error';
const isSecurityViolation = error.includes('Security violation') || error.includes('not whitelisted');

let title, message, topic, priority, sendToSlack;

if (isSecurityViolation) {
  title = '🔴 SECURITY VIOLATION: Script Executor';
  message = `Security violation detected!\n\nError: ${error}\n\nImmediate investigation required.`;
  topic = 'hwc-critical';
  priority = 5;
  sendToSlack = true;
} else {
  title = '⚠️ Script Executor Error';
  message = `Error in script executor workflow.\n\nError: ${error}`;
  topic = 'hwc-alerts';
  priority = 4;
  sendToSlack = false;
}

return {
  json: {
    title,
    message,
    topic,
    priority,
    tags: 'error,script-executor,security',
    sendToSlack
  }
};
